95	const THROTTLE_SECS = 6 * 60 * 60;
96	const APIFY_WAIT_SECS = 60;
97	const APIFY_TERMINAL_EVENTS = [
98	  "ACTOR.RUN.SUCCEEDED",
99	  "ACTOR.RUN.FAILED",
100	  "ACTOR.RUN.TIMED_OUT",
101	  "ACTOR.RUN.ABORTED",
102	];
103	const UUID_RE =
104	  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
105	
106	type MetricsKey = "tiktok" | "ig_details" | "ig_posts";
107	type MetricsStatus = "fresh" | "refreshing" | "failed";
108	
109	interface RefreshRequest {
110	  social_link_id?: unknown;
111	}
112	
113	interface SocialLinkRow {
114	  id: string;
115	  user_id: string;
116	  platform: "tiktok" | "instagram";
117	  handle: string;
118	  status: string;
119	  last_scrape_attempt_at: string | null;
120	}
