136	Deno.serve(async (req) => {
137	  if (req.method === "OPTIONS") {
138	    return new Response(null, { status: 204, headers: corsHeaders });
139	  }
140	  if (req.method !== "POST") {
141	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
142	  }
143	
144	  const token = bearerToken(req);
145	  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });
146	
147	  let claims;
148	  try {
149	    claims = await verifyJwt(token);
150	  } catch {
151	    return jsonResponse(401, { error: "UNAUTHORIZED" });
152	  }
153	  if (claims.role !== "creator") {
154	    return jsonResponse(403, { error: "FORBIDDEN" });
155	  }
156	
157	  let body: RefreshRequest;
158	  try {
159	    body = await req.json();
160	  } catch {
161	    return jsonResponse(400, { error: "INVALID_JSON" });
162	  }
163	
164	  const socialLinkId =
165	    typeof body.social_link_id === "string" &&
166	    UUID_RE.test(body.social_link_id)
167	      ? body.social_link_id
168	      : null;
169	  if (!socialLinkId) {
170	    return jsonResponse(400, { error: "INVALID_REQUEST" });
171	  }
172	
173	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
174	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
175	  const apifyKey = Deno.env.get("APIFY_KEY");
176	  const webhookSecret = Deno.env.get("APIFY_WEBHOOK_SECRET");
177	  if (!supabaseUrl || !serviceRoleKey || !apifyKey || !webhookSecret) {
178	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
179	  }
180	
181	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
182	    auth: { persistSession: false, autoRefreshToken: false },
183	  });
184	
185	  const { data: link, error: linkError } = await supabase
186	    .from("social_links")
187	    .select(
188	      "id,user_id,platform,handle,status,last_scrape_attempt_at",
189	    )
190	    .eq("id", socialLinkId)
191	    .maybeSingle();
192	
193	  if (linkError) {
194	    console.error("social_links lookup failed", linkError);
195	    return jsonResponse(500, { error: "DB_ERROR" });
196	  }
197	  const row = link as SocialLinkRow | null;
198	  if (!row || row.user_id !== claims.sub) {
199	    // 404 rather than 403 so the endpoint doesn't leak which ids exist
200	    // for other creators.
201	    return jsonResponse(404, { error: "LINK_NOT_FOUND" });
202	  }
203	  if (row.status === "unlinked") {
204	    return jsonResponse(422, { error: "LINK_UNLINKED" });
205	  }
206	
207	  const requiredModes = requiredScrapeModes(row.platform);
208	  const nowMs = Date.now();
209	  const cutoffIso = new Date(nowMs - THROTTLE_SECS * 1000).toISOString();
210	
211	  // already_fresh short-circuit: the creator already has current data for
212	  // every required mode, so we skip Apify and return the existing ids.
213	  // Runs BEFORE the throttle bump so a caller who polls repeatedly while
214	  // data is fresh doesn't burn their 6h window.
215	  const freshSnapshots = await fetchLatestFreshSnapshots(
216	    supabase,
217	    row.id,
218	    requiredModes,
219	    cutoffIso,
220	  );
221	  if (freshSnapshots === "db_error") {
222	    return jsonResponse(500, { error: "DB_ERROR" });
223	  }
224	  if (freshSnapshots.size === requiredModes.length) {
225	    const alreadyFreshMetrics: Partial<Record<MetricsKey, MetricsStatus>> = {};
226	    for (const mode of requiredModes) {
227	      alreadyFreshMetrics[modeToMetricsKey(mode)] = "fresh";
228	    }
229	    return jsonResponse(200, {
230	      status: "already_fresh",
231	      snapshot_ids: requiredModes.map((m) => freshSnapshots.get(m)!),
232	      metrics_status: alreadyFreshMetrics,
233	    });
234	  }
